5	using Microsoft.AspNetCore.Components;
6	using Microsoft.AspNetCore.Components.Forms;
7	using Microsoft.AspNetCore.Components.Web;
8	using Microsoft.Extensions.Logging;
9	using Microsoft.JSInterop;
10	using MudBlazor.Resources;
11	using MudBlazor.State;
12	using MudBlazor.Utilities;
13	
14	namespace MudBlazor
15	{
16	
17	    /// <summary>
18	    /// A form component that lets users upload one or more files.
19	    /// </summary>
20	    /// <typeparam name="T">Use <see cref="IBrowserFile"/> for a single file or <see cref="IReadOnlyList{IBrowserFile}">IReadOnlyList&lt;IBrowserFile&gt;</see> for multiple files.</typeparam>
21	    public partial class MudFileUpload<T> : MudFormComponent<T, string>
22	    {
23	        private readonly ParameterState<T?> _filesState;
24	        private readonly ParameterState<bool> _draggingState;
25	
26	        [Inject]
27	        private IJSRuntime JsRuntime { get; set; } = null!;
28	
29	        [Inject]
30	        private InternalMudLocalizer Localizer { get; set; } = null!;
31	
32	        /// <summary>
33	        /// Creates a new instance.
34	        /// </summary>
35	        public MudFileUpload()
36	        {
37	            using var registerScope = CreateRegisterScope();
38	            _filesState = registerScope.RegisterParameter<T?>(nameof(Files))
39	                .WithParameter(() => Files)
40	                .WithEventCallback(() => FilesChanged);
41	            _draggingState = registerScope.RegisterParameter<bool>(nameof(Dragging))
42	                .WithParameter(() => Dragging)
43	                .WithEventCallback(() => DraggingChanged);
44	        }
45	
46	        private readonly string _id = Identifier.Create();
47	        private readonly List<string> _validationErrors = [];
48	
49	        protected string Classname =>
50	            new CssBuilder("mud-file-upload")
51	                .AddClass(Class)
52	                .Build();
53	
54	        protected string DragClass =>
55	            new CssBuilder("mud-file-upload-dragarea")
56	                .AddClass("mud-file-upload-dragarea-clickable", !GetDisabledState())
57	                .AddClass("mud-border-primary", _draggingState.Value)
58	                .Build();
59	
60	        protected string InputClasses =>
61	            new CssBuilder(InputClass)
62	                .AddClass("mud-file-upload-dragover", DragAndDrop && (Hidden || CustomContent == null))
63	                .Build();
64	
65	        /// <summary>
66	        /// The selected file or files.
67	        /// </summary>
68	        /// <remarks>
69	        /// When <c>T</c> is <see cref="IBrowserFile" />, a single file is provided.<br />
70	        /// When <c>T</c> is <see cref="IReadOnlyList{IBrowserFile}">IReadOnlyList&lt;IBrowserFile&gt;</see>, multiple files are provided.
71	        /// </remarks>
72	        [Parameter, ParameterState]
73	        [Category(CategoryTypes.FileUpload.Behavior)]
74	        public T? Files { get; set; }
75	
76	        /// <summary>
77	        /// Occurs when <see cref="Files"/> has changed.
78	        /// </summary>
79	        [Parameter]
80	        [Category(CategoryTypes.FileUpload.Behavior)]
81	        public EventCallback<T?> FilesChanged { get; set; }
82	
83	        /// <summary>
84	        /// Occurs when <see cref="Dragging"/> has changed.
85	        /// </summary>
86	        [Parameter]
87	        [Category(CategoryTypes.FileUpload.Behavior)]
88	        public EventCallback<bool> DraggingChanged { get; set; }
89	
90	        /// <summary>
91	        /// Occurs when the user selects or drops files.
92	        /// </summary>
93	        /// <remarks>
94	        /// Not raised when <see cref="SuppressOnChangeWhenInvalid"/> is <c>true</c> and validation fails.
95	        /// </remarks>
96	        [Parameter]
97	        [Category(CategoryTypes.FileUpload.Behavior)]
98	        public EventCallback<InputFileChangeEventArgs> OnFilesChanged { get; set; }
99	
100	        /// <summary>
101	        /// Appends new files to the existing selection.
102	        /// </summary>
103	        /// <remarks>
104	        /// Defaults to <c>false</c>.  This applies when <c>T</c> is <see cref="IReadOnlyList{IBrowserFile}">IReadOnlyList&lt;IBrowserFile&gt;</see>.
105	        /// </remarks>
106	        [Parameter]
107	        [Category(CategoryTypes.FileUpload.Behavior)]
108	        public bool AppendMultipleFiles { get; set; }
109	
110	        /// <summary>
111	        /// The custom content used to render the upload UI.
112	        /// </summary>
113	        /// <remarks>
114	        /// The context is the current <see cref="MudFileUpload{T}"/> instance and can be used to call <see cref="OpenFilePickerAsync"/>.
115	        /// </remarks>
116	        [Parameter]
117	        [Category(CategoryTypes.FileUpload.Behavior)]
118	        public RenderFragment<MudFileUpload<T>>? CustomContent { get; set; }
119	
120	        /// <summary>
121	        /// The template used to render selected files.
122	        /// </summary>
123	        /// <remarks>
124	        /// When <c>null</c>, a default chip list is shown.
125	        /// </remarks>
126	        [Parameter]
127	        [Category(CategoryTypes.FileUpload.Appearance)]
128	        public RenderFragment<T?>? SelectedTemplate { get; set; }
129	
130	        /// <summary>
131	        /// Prevents raising <see cref="OnFilesChanged"/> when validation fails during an upload.
132	        /// </summary>
133	        /// <remarks>
134	        /// Defaults to <c>false</c>.
135	        /// </remarks>
136	        [Parameter]
137	        [Category(CategoryTypes.FileUpload.Behavior)]
138	        public bool SuppressOnChangeWhenInvalid { get; set; }
139	
140	        /// <summary>
141	        /// The accepted file types for the file picker.
142	        /// </summary>
143	        /// <remarks>
144	        /// Defaults to <c>null</c> for any file type.  Multiple file types must be separated by commas (e.g. <c>".png,.jpg"</c>).
145	        /// </remarks>
146	        [Parameter]
147	        [Category(CategoryTypes.FileUpload.Behavior)]
148	        public string? Accept { get; set; }
149	
150	        /// <summary>
151	        /// Hides the internal <see cref="InputFile"/> element.
152	        /// </summary>
153	        /// <remarks>
154	        /// Defaults to <c>true</c>.  When <c>false</c>, the input is visible.
155	        /// </remarks>
156	        [Parameter]
157	        [Category(CategoryTypes.FileUpload.Appearance)]
158	        public bool Hidden { get; set; } = true;
159	
160	        /// <summary>
161	        /// Enables a drag-and-drop area inside the component.
162	        /// </summary>
163	        /// <remarks>
164	        /// Defaults to <c>false</c>.  During drag operations, the internal <see cref="InputFile"/> element can be shown to capture drop events even when <see cref="Hidden"/> is <c>true</c>.
165	        /// </remarks>
166	        [Parameter]
167	        [Category(CategoryTypes.FileUpload.Behavior)]
168	        public bool DragAndDrop { get; set; }
169	
170	        /// <summary>
171	        /// Indicates whether a drag operation is active.
172	        /// </summary>
173	        /// <remarks>
174	        /// When <c>true</c>, the internal <see cref="InputFile"/> element is shown to capture the drop, which temporarily overrides <see cref="Hidden"/>.  When <c>false</c>, visibility follows <see cref="Hidden"/> again.  Drop-related events reset it to <c>false</c>.
175	        /// </remarks>
176	        [Parameter]
177	        [Category(CategoryTypes.FileUpload.Behavior)]
178	        public bool Dragging { get; set; }
179	
180	        /// <summary>
181	        /// The CSS classes applied to the internal <see cref="InputFile"/> element.
182	        /// </summary>
183	        /// <remarks>
184	        /// Defaults to <c>null</c>.  These classes apply when <see cref="Hidden"/> is <c>false</c>.  Multiple classes must be separated by spaces.
185	        /// </remarks>
186	        [Parameter]
187	        [Category(CategoryTypes.FileUpload.Appearance)]
188	        public string? InputClass { get; set; }
189	
190	        /// <summary>
191	        /// The CSS styles applied to the internal <see cref="InputFile"/> element.
192	        /// </summary>
193	        /// <remarks>
194	        /// Defaults to <c>null</c>.  These styles apply when <see cref="Hidden"/> is <c>false</c>.  Prefer <see cref="InputClass"/>.
195	        /// </remarks>
196	        [Obsolete("Prefer the InputClass property with CSS https://github.com/MudBlazor/MudBlazor/issues/12047")]
197	        [Parameter]
198	        [Category(CategoryTypes.FileUpload.Appearance)]
199	        public string? InputStyle { get; set; }
200	
201	        /// <summary>
202	        /// The maximum number of files retrieved per selection.
203	        /// </summary>
204	        /// <remarks>
205	        /// Defaults to <c>10</c>.  This does not limit the total number of files; enforce overall limits in <see cref="FilesChanged"/>.
206	        /// </remarks>
207	        [Parameter]
208	        [Category(CategoryTypes.FileUpload.Behavior)]
209	        public int MaximumFileCount { get; set; } = 10;
210	
211	        /// <summary>
212	        /// The maximum allowed file size in bytes.
213	        /// </summary>
214	        /// <remarks>
215	        /// Defaults to <c>null</c> (no limit).  Files exceeding this limit are rejected and a validation error is added.
216	        /// </remarks>
217	        [Parameter]
218	        [Category(CategoryTypes.FileUpload.Behavior)]
219	        public long? MaxFileSize { get; set; }
220	
221	        /// <summary>
222	        /// Prevents the user from interacting with this component.
223	        /// </summary>
224	        /// <remarks>
225	        /// Defaults to <c>false</c>.
226	        /// </remarks>
227	        [Parameter]
228	        [Category(CategoryTypes.FileUpload.Behavior)]
229	        public bool Disabled { get; set; }
230	
231	        [CascadingParameter(Name = "ParentDisabled")]
232	        private bool ParentDisabled { get; set; }
233	
234	        [CascadingParameter(Name = "ParentReadOnly")]
235	        private bool ParentReadOnly { get; set; }
236	
237	        /// <summary>
238	        /// Returns the filenames for the selected files.
239	        /// </summary>
240	        /// <remarks>
241	        /// When <c>T</c> is <see cref="IBrowserFile" />, a single filename is returned.<br />
242	        /// When <c>T</c> is <see cref="IReadOnlyList{IBrowserFile}">IReadOnlyList&lt;IBrowserFile&gt;</see>, multiple filenames are returned.
243	        /// </remarks>
244	        public IReadOnlyList<string> GetFilenames()
245	        {
246	            if (EqualityComparer<T>.Default.Equals(_filesState.Value, default))
247	            {
248	                return [];
249	            }
250	            return _filesState.Value switch
251	            {
252	                IBrowserFile singleFile => [singleFile.Name],
253	                IReadOnlyList<IBrowserFile> fileList => fileList.Select(f => f.Name).ToList(),
254	                _ => []
255	            };
256	        }
257	
258	        protected bool GetDisabledState() => Disabled || ParentDisabled || ParentReadOnly;
259	
260	        private async Task OnDragResetAsync()
261	        {
262	            await _draggingState.SetValueAsync(false);
263	        }
264	
265	        private Task OnDragAreaClickAsync()
266	        {
267	            if (GetDisabledState())
268	            {
269	                return Task.CompletedTask;
270	            }
271	
272	            return OpenFilePickerAsync();
273	        }
274	
275	        private Task OnDragEnterAsync()
276	        {
277	            if (GetDisabledState())
278	            {
279	                return Task.CompletedTask;
280	            }
281	
282	            return _draggingState.SetValueAsync(true);
283	        }
284	
285	        private Task OnFileChipCloseAsync(string filename)
286	        {
287	            if (GetDisabledState())
288	            {
289	                return Task.CompletedTask;
290	            }
291	
292	            return RemoveFileAsync(filename);
293	        }
294	
295	        private int _numberOfActiveFileInputs = 1;
296	        private string? GetInputClass(int fileInputIndex) => fileInputIndex == _numberOfActiveFileInputs
297	            ? InputClasses
298	            : $"{InputClasses} d-none";
299	        private string GetInputId(int fileInputIndex) => $"{_id}-{fileInputIndex}";
300	        private string GetActiveInputId() => $"{_id}-{_numberOfActiveFileInputs}";
301	
302	        /// <summary>
303	        /// Removes all files with the specified name from <see cref="Files"/>.
304	        /// </summary>
305	        /// <param name="filename">The name of the file(s) to remove.</param>
306	        /// <returns>
307	        /// <c>true</c> if one or more files were removed; otherwise, <c>false</c>
308	        /// if no file with the specified name exists in the current selection.
309	        /// </returns>
310	        public async Task<bool> RemoveFileAsync(string filename)
311	        {
312	            if (string.IsNullOrWhiteSpace(filename))
313	            {
314	                Logger.LogWarning("Attempted to remove a file with an invalid filename.");
315	                return false;
316	            }
317	
318	            var current = _filesState.Value;
319	
320	            switch (current)
321	            {
322	                case IBrowserFile singleFile when singleFile.Name == filename:
323	                    // Single selection with matching name: clear selection
324	                    await _filesState.SetValueAsync(default);
325	                    return true;
326	
327	                case IReadOnlyList<IBrowserFile> fileList:
328	                    {
329	                        var updatedList = fileList.Where(f => f.Name != filename).ToList();
330	                        if (updatedList.Count == fileList.Count)
331	                        {
332	                            Logger.LogDebug("File '{Filename}' not found in the current selection.", filename);
333	                            return false;
334	                        }
335	
336	                        if (updatedList.Count == 0)
337	                        {
338	                            // Treat removal of the last file as "no selection"
339	                            await _filesState.SetValueAsync(default);
340	                        }
341	                        else
342	                        {
343	                            // T is expected to be IReadOnlyList<IBrowserFile> here
344	                            await _filesState.SetValueAsync((T)(object)updatedList);
345	                        }
346	
347	                        return true;
348	                    }
349	
350	                case null:
351	                    Logger.LogDebug("No files are currently selected.");
352	                    return false;
353	
354	                default:
355	                    Logger.LogWarning(
356	                        "File removal by name is not supported for the current files type '{Type}'.",
357	                        current.GetType().FullName);
358	                    return false;
359	            }
360	        }
361	
362	        /// <summary>
363	        /// Removes the specified file instance from <see cref="Files"/>.
364	        /// </summary>
365	        /// <param name="file">The file instance to remove.</param>
366	        /// <returns>
367	        /// <c>true</c> if the specified file instance was removed; otherwise, <c>false</c>.
368	        /// </returns>
369	        public async Task<bool> RemoveFileAsync(IBrowserFile file)
370	        {
371	            if (file is null)
372	            {
373	                Logger.LogWarning("Attempted to remove a null file.");
374	                return false;
375	            }
376	
377	            var current = _filesState.Value;
378	
379	            switch (current)
380	            {
381	                case IBrowserFile singleFile when ReferenceEquals(singleFile, file):
382	                    // Single selection with the same instance: clear selection
383	                    await _filesState.SetValueAsync(default);
384	                    return true;
385	
386	                case IReadOnlyList<IBrowserFile> fileList:
387	                    {
388	                        // Remove this specific instance (reference-based via List.Remove)
389	                        var updatedList = fileList.ToList();
390	                        if (!updatedList.Remove(file))
391	                        {
392	                            Logger.LogDebug("The specified file instance was not found in the current selection.");
393	                            return false;
394	                        }
395	
396	                        if (updatedList.Count == 0)
397	                        {
398	                            await _filesState.SetValueAsync(default);
399	                        }
400	                        else
401	                        {
402	                            await _filesState.SetValueAsync((T)(object)updatedList);
403	                        }
404	
405	                        return true;
406	                    }
407	
408	                case null:
409	                    Logger.LogDebug("No files are currently selected.");
410	                    return false;
411	
412	                default:
413	                    Logger.LogWarning(
414	                        "File removal by instance is not supported for the current files type '{Type}'.",
415	                        current.GetType().FullName);
416	                    return false;
417	            }
418	        }
419	
420	
421	        /// <summary>
422	        /// Clears the selected files and resets the internal file inputs.
423	        /// </summary>
424	        /// <remarks>
425	        /// This also removes validation errors produced by file size checks.
426	        /// </remarks>
427	        public async Task ClearAsync()
428	        {
429	            ValidationErrors.RemoveAll(_validationErrors.Contains);
430	
431	            _validationErrors.Clear();
432	            _numberOfActiveFileInputs = 1;
433	
434	            await NotifyValueChangedAsync(default);
435	            await JsRuntime.InvokeVoidAsyncWithErrorHandling("mudInput.resetValue", GetActiveInputId());
436	        }
437	
438	        /// <summary>
439	        /// Opens the native file picker for the active input.
440	        /// </summary>
441	        public async Task OpenFilePickerAsync()
442	            => await JsRuntime.InvokeVoidAsyncWithErrorHandling("mudFileUpload.openFilePicker", GetActiveInputId());
443	
444	        private async Task OnChangeAsync(InputFileChangeEventArgs args)
445	        {
446	            _numberOfActiveFileInputs++;
447	
448	            if (GetDisabledState())
449	                return;
450	
451	            await ProcessFileChangeAsync(args);
452	        }
453	
454	        private async Task ProcessFileChangeAsync(InputFileChangeEventArgs args)
455	        {
456	            T? value;
457	
458	            if (args.FileCount > MaximumFileCount)
459	            {
460	                // Notify the consumer about the exceeded file count
461	                _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_MaximumFileCountExceeded, args.FileCount, MaximumFileCount]);
462	                await NotifyValueChangedAsync(default); // Reset the value to indicate no valid files were processed
463	                return;
464	            }
465	
466	            if (typeof(T) == typeof(IReadOnlyList<IBrowserFile>))
467	            {
468	                value = (T?)(object)ProcessMultipleFiles(args.GetMultipleFiles(MaximumFileCount));
469	            }
470	            else if (typeof(T) == typeof(IBrowserFile))
471	            {
472	                value = (T?)ProcessSingleFile(args.FileCount == 1 ? args.File : null);
473	            }
474	            else
475	            {
476	                return;
477	            }
478	
479	            await NotifyValueChangedAsync(value);
480	
481	            if (!ErrorState.Value || !SuppressOnChangeWhenInvalid)
482	                await OnFilesChanged.InvokeAsync(args);
483	        }
484	
485	        private IReadOnlyList<IBrowserFile> ProcessMultipleFiles(IReadOnlyCollection<IBrowserFile> files)
486	        {
487	            var validFiles = new List<IBrowserFile>();
488	
489	            foreach (var file in files)
490	            {
491	                if (MaxFileSize.HasValue && file.Size > MaxFileSize.Value)
492	                {
493	                    _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_FileSizeError, file.Name, MaxFileSize.Value.ToString()]);
494	                }
495	                else
496	                {
497	                    validFiles.Add(file);
498	                }
499	            }
500	
501	            var newFiles = validFiles.AsReadOnly();
502	
503	            if (AppendMultipleFiles && _filesState.Value is IReadOnlyList<IBrowserFile> oldFiles)
504	                return oldFiles.Concat(newFiles).ToList().AsReadOnly();
505	
506	            return newFiles;
507	        }
508	
509	        private IBrowserFile? ProcessSingleFile(IBrowserFile? file)
510	        {
511	            if (file == null)
512	                return null;
513	
514	            if (MaxFileSize.HasValue && file.Size > MaxFileSize.Value)
515	            {
516	                _validationErrors.Add(Localizer[LanguageResource.MudFileUpload_FileSizeError, file.Name, MaxFileSize.Value.ToString()]);
517	                return null;
518	            }
519	
520	            return file;
521	        }
522	
523	        protected override void OnInitialized()
524	        {
525	            if (!(typeof(T) == typeof(IReadOnlyList<IBrowserFile>) || typeof(T) == typeof(IBrowserFile)))
526	            {
527	                Logger.LogWarning("T must be of type {type1} or {type2}", typeof(IReadOnlyList<IBrowserFile>), typeof(IBrowserFile));
528	            }
529	
530	            base.OnInitialized();
531	        }
532	
533	        private async Task NotifyValueChangedAsync(T? value)
534	        {
535	            Touched = true;
536	            await _filesState.SetValueAsync(value);
537	            await BeginValidateAsync();
538	            FieldChanged(value);
539	        }
540	
541	        /// <inheritdoc />
542	        protected override IConverter<T?, string?> GetDefaultConverter()
543	        {
544	            return new DefaultConverter<T>
545	            {
546	                Culture = GetCulture,
547	                Format = GetFormat
548	            };
549	        }
550	
551	        protected internal override T? ReadValue => _filesState.Value;
552	
553	        protected override Task SetValueCoreAsync(T? value) => _filesState.SetValueAsync(value);
554	
555	        protected override async Task ValidateValue()
556	        {
557	            await base.ValidateValue();
558	
559	            ValidationErrors = [.. ValidationErrors, .. _validationErrors];
560	            await ErrorState.SetValueAsync(ValidationErrors.Count > 0);
561	            await ErrorTextState.SetValueAsync(ValidationErrors.FirstOrDefault());
562	        }
563	
564	        /// <inheritdoc />
565	        public override Task ResetValidationAsync()
566	        {
567	            _validationErrors.Clear();
568	
569	            return base.ResetValidationAsync();
570	        }
571	    }
572	}
573	

