@using System.IO

<style>
    .file-upload-input {
        position: absolute;
        width: 100%;
        height: 100%;
        overflow: hidden;
        z-index: 20;
        opacity: 0;
    }
</style>

<MudFileUpload T="IBrowserFile"
               @ref="@_fileUpload"
               @bind-Files="File"
               @bind-Files:after="@OnFilesChangedAsync"
               Accept=".png,.jpg,.jpeg"
               Hidden="@false"
               tabindex="-1"
               @ondrop="@ClearDragClass"
               @ondragenter="@SetDragClass"
               @ondragleave="@ClearDragClass"
               @ondragend="@ClearDragClass">
    <CustomContent>
        <MudPaper Height="300px"
                  Outlined="true"
                  Class="@_dragClass" @onclick="@context.OpenFilePickerAsync">
            <MudText Typo="Typo.h6">
                Drag and drop files here or click
            </MudText>
            <MudChip T="string"
                     Color="Color.Dark"
                     Text="@File?.Name"
                     tabindex="-1" />
            <br>
            <MudImage Class="rounded"
                      Height="200"
                      Src="@_imageSource" />
        </MudPaper>
    </CustomContent>
</MudFileUpload>
<MudToolBar Gutters="@false"
            Class="relative d-flex justify-end gap-4">
    <MudButton id="open-file-picker-button"
               OnClick="@OpenFilePickerAsync">
        Open file picker
    </MudButton>
    <MudButton id="clear-button"
               OnClick="@ClearAsync">
        Clear
    </MudButton>
</MudToolBar>

@code {
    public static string __description__ = "Tests drag-and-drop activator behavior with preview, open picker, and clear actions.";

    [Parameter]
    public IBrowserFile? File { get; set; }

    private MudFileUpload<IBrowserFile>? _fileUpload;

    private string? _imageSource;

    private const string DefaultDragClass = "relative rounded-lg border-2 border-dashed pa-4 mud-width-full mud-height-full";
    private string _dragClass = DefaultDragClass;

    private void SetDragClass()
        => _dragClass = $"{DefaultDragClass} mud-border-primary";

    private void ClearDragClass()
        => _dragClass = DefaultDragClass;

    private Task OpenFilePickerAsync()
        => _fileUpload?.OpenFilePickerAsync() ?? Task.CompletedTask;

    private Task ClearAsync()
    {
        _imageSource = null;
        return _fileUpload?.ClearAsync() ?? Task.CompletedTask;
    }

    private async Task OnFilesChangedAsync()
    {
        if (File is null)
        {
            return;
        }

        using var memoryStream = new MemoryStream();
        await File.OpenReadStream(int.MaxValue).CopyToAsync(memoryStream);
        var buffer = memoryStream.ToArray();

        _imageSource = ConvertByteToImage(File.ContentType, buffer);
        StateHasChanged();
    }

    private static string ConvertByteToImage(string contentType, byte[] buffer)
        => $"data:{contentType};base64,{Convert.ToBase64String(buffer)}";
}

