        [Test]
        public void FileUpload_Multiple()
        {
            var comp = Context.Render<MudFileUpload<IReadOnlyList<IBrowserFile>>>();

            var input = comp.Find("input");
            input.HasAttribute("multiple").Should().BeTrue();
        }

